/**
 * @summary List appraisals (filtered by role)
 */
export const getListAppraisalsUrl = (params?: ListAppraisalsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/appraisals?${stringifiedParams}`
    : `/api/appraisals`;
};

export const listAppraisals = async (
  params?: ListAppraisalsParams,
  options?: RequestInit,
): Promise<Appraisal[]> => {
  return customFetch<Appraisal[]>(getListAppraisalsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListAppraisalsQueryKey = (params?: ListAppraisalsParams) => {
  return [`/api/appraisals`, ...(params ? [params] : [])] as const;
};

